mapper.select:
SELECT * FROM t_product
WHERE merchant_id = #{merchantId} AND deleted = 0

    AND (product_name LIKE CONCAT('%', #{keyword}, '%')
         OR category_id LIKE CONCAT('%', #{keyword}, '%')
         OR store_code LIKE CONCAT('%', #{keyword}, '%'))


    AND DATE(created_time) >= #{startDate}


    AND DATE(created_time) <= #{endDate}

ORDER BY created_time DESC
LIMIT #{offset}, #{limit}
